previewCss:
.darma-loader-darma-custom-564 {color: var(--loader-color, #6d28d9);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
   height: 3px;
   width: 60px;
   background: linear-gradient(currentColor 0 0) right/51% 100% no-repeat;
   display: flex;
   animation: darma-loader-darma-custom-564-l10-0 2s linear infinite;
}
.darma-loader-darma-custom-564:before, .darma-loader-darma-custom-564:after  {
  content: "";
   width: 15px;
   background: currentColor;
   animation: darma-loader-darma-custom-564-l10-1 2s linear infinite;
}
.darma-loader-darma-custom-564:after  {
  animation-delay: -1s;
   --s:-1;
}
@keyframes darma-loader-darma-custom-564-l10-1  {
  0%,100%{transform:scaleX(var(--s,1)) rotate(0)}
25%,75% {transform:scaleX(var(--s,1)) rotate(180deg)}
}
@keyframes darma-loader-darma-custom-564-l10-0  {
  0%,49.9%{transform:scaleX( 1)}
50%,100%{transform:scaleX(-1)}
}

